31	fn parse_ternary(ts: &mut TokenStream) -> Result<Expr, CompileError> {
32	    let cond = parse_log_or(ts)?;
33	    if ts.eat(TokenKind::Question) {
34	        let then_expr = parse_expr(ts)?;
35	        ts.expect(TokenKind::Colon)?;
36	        let else_expr = parse_ternary(ts)?;
37	        return Ok(Expr::Ternary {
