46	pub fn parse_unary(ts: &mut TokenStream) -> Result<Expr, CompileError> {
47	    if ts.eat(TokenKind::Sizeof) {
48	        return parse_sizeof(ts);
49	    }
50	    if ts.eat(TokenKind::Plus) {
51	        // Unary + is identity, just parse the operand
52	        return parse_unary(ts);
53	    }
54	    if ts.eat(TokenKind::Minus) {
55	        let operand = parse_unary(ts)?;
56	        return Ok(Expr::UnaryOp {
57	            op: UnaryOp::Neg,
58	            operand: Box::new(operand),
59	        });
60	    }
61	    if ts.eat(TokenKind::Tilde) {
62	        let operand = parse_unary(ts)?;
63	        return Ok(Expr::UnaryOp {
64	            op: UnaryOp::BitNot,
65	            operand: Box::new(operand),
66	        });
67	    }
68	    if ts.eat(TokenKind::Bang) {
69	        let operand = parse_unary(ts)?;
70	        return Ok(Expr::UnaryOp {
71	            op: UnaryOp::LogNot,
72	            operand: Box::new(operand),
73	        });
74	    }
75	    if ts.eat(TokenKind::PlusPlus) {
76	        let name = ts.expect_ident()?;
77	        return Ok(Expr::PreInc(name));
78	    }
