83	    if ts.eat(TokenKind::Amp) {
84	        let name = ts.expect_ident()?;
85	        // Check for postfix: &arr[i], &s.field, etc.
86	        if ts.check(&TokenKind::LBracket) || ts.check(&TokenKind::Dot) || ts.check(&TokenKind::Arrow) {
87	            let base = Expr::Ident(name);
88	            let postfix = parse_postfix_chain(ts, base)?;
89	            // &arr[i] is equivalent to arr + i (pointer arithmetic),
90	            // and arr[i] is already desugared to *(arr + i) by parse_postfix_chain.
