97	            return Ok(Expr::AddrOf(String::new())); // fallback (shouldn't reach)
98	        }
99	        return Ok(Expr::AddrOf(name));
100	    }
101	    if ts.eat(TokenKind::Star) {
102	        let operand = parse_unary(ts)?;
103	        return Ok(Expr::Deref(Box::new(operand)));
