111	        if ts.check(&TokenKind::LBrace) {
112	            let block = parse_block(ts)?;
113	            ts.expect(TokenKind::RParen)?;
114	            return parse_postfix_chain(ts, Expr::StmtExpr(block));
115	        }
116	        // Cast: (type)expr  vs  parenthesized: (expr)
117	        if is_type_start(ts) {
118	            let ty = parse_type(ts)?;
119	            ts.expect(TokenKind::RParen)?;
120	            let operand = parse_unary(ts)?;
121	            let cast = Expr::Cast {
122	                ty,
123	                expr: Box::new(operand),
124	            };
125	            return parse_postfix_chain(ts, cast);
126	        }
127	        let expr = parse_expr(ts)?;
128	        ts.expect(TokenKind::RParen)?;
129	        return parse_postfix_chain(ts, expr);
130	    }
131	    if let TokenKind::IntLit(_) = &ts.peek().kind {
132	        let TokenKind::IntLit(val) = ts.advance().kind else {
133	            unreachable!()
134	        };
135	        return Ok(Expr::IntLit(val));
136	    }
137	    if let TokenKind::StringLit(_) = &ts.peek().kind {
138	        let TokenKind::StringLit(mut s) = ts.advance().kind else {
139	            unreachable!()
140	        };
141	        // C89 implicit string literal concatenation: "a" "b" → "ab"
142	        while let TokenKind::StringLit(_) = &ts.peek().kind {
143	            let TokenKind::StringLit(next) = ts.advance().kind else {
144	                unreachable!()
145	            };
146	            s.push_str(&next);
147	        }
148	        return Ok(Expr::StringLit(s));
149	    }
150	    if let TokenKind::Ident(_) = &ts.peek().kind {
151	        return parse_ident_or_call(ts);
152	    }
153	    Err(CompileError::new(
154	        format!("expected expression, got {:?}", ts.peek().kind),
155	        Some(ts.current_span()),
156	    ))
157	}
158	
159	fn parse_ident_or_call(ts: &mut TokenStream) -> Result<Expr, CompileError> {
160	    let TokenKind::Ident(name) = ts.advance().kind else {
161	        unreachable!()
162	    };
163	    // Resolve enum constants to integer literals
164	    if let Some(&val) = ts.enum_constants.get(&name) {
165	        return Ok(Expr::IntLit(val));
166	    }
167	    // Function call: foo(args...)
168	    if ts.eat(TokenKind::LParen) {
169	        let mut args = Vec::new();
170	        if !ts.check(&TokenKind::RParen) {
171	            loop {
172	                args.push(parse_expr(ts)?);
173	                if !ts.eat(TokenKind::Comma) {
174	                    break;
175	                }
176	            }
177	        }
178	        ts.expect(TokenKind::RParen)?;
179	        let call = Expr::Call { name, args };
180	        return parse_postfix_chain(ts, call);
181	    }
182	    // Postfix ++/-- (these consume the name, not chainable)
183	    if ts.eat(TokenKind::PlusPlus) {
184	        return Ok(Expr::PostInc(name));
185	    }
186	    if ts.eat(TokenKind::MinusMinus) {
187	        return Ok(Expr::PostDec(name));
188	    }
189	    // Start with the identifier, then chain postfix ops: [], ., ->
190	    let mut result = Expr::Ident(name);
191	    result = parse_postfix_chain(ts, result)?;
192	    Ok(result)
193	}
