195	/// Parse chained postfix operations: a[i].b->c[j] etc.
196	fn parse_postfix_chain(ts: &mut TokenStream, mut expr: Expr) -> Result<Expr, CompileError> {
197	    loop {
198	        if ts.eat(TokenKind::LBracket) {
199	            let index = parse_expr(ts)?;
200	            ts.expect(TokenKind::RBracket)?;
201	            expr = Expr::Deref(Box::new(Expr::BinOp {
202	                op: tc24r_ast::BinOp::Add,
203	                lhs: Box::new(expr),
204	                rhs: Box::new(index),
205	            }));
206	        } else if ts.eat(TokenKind::LParen) {
207	            // Indirect call: expr(args) — for table[n](arg), (*fp)(arg), etc.
208	            let mut args = Vec::new();
209	            if !ts.check(&TokenKind::RParen) {
210	                loop {
211	                    args.push(parse_expr(ts)?);
212	                    if !ts.eat(TokenKind::Comma) {
213	                        break;
214	                    }
215	                }
216	            }
217	            ts.expect(TokenKind::RParen)?;
218	            expr = Expr::IndirectCall {
219	                callee: Box::new(expr),
220	                args,
221	            };
222	        } else if ts.eat(TokenKind::Dot) {
223	            let member = ts.expect_ident()?;
224	            expr = Expr::MemberAccess {
225	                object: Box::new(expr),
226	                member,
227	            };
228	        } else if ts.eat(TokenKind::Arrow) {
229	            let member = ts.expect_ident()?;
230	            expr = Expr::MemberAccess {
231	                object: Box::new(Expr::Deref(Box::new(expr))),
232	                member,
233	            };
234	        } else {
235	            break;
236	        }
237	    }
238	    Ok(expr)
239	}
