241	/// Parse `sizeof(type)` or `sizeof(expr)` after the `sizeof` token.
242	fn parse_sizeof(ts: &mut TokenStream) -> Result<Expr, CompileError> {
243	    ts.expect(TokenKind::LParen)?;
244	    if is_type_start(ts) {
245	        let mut ty = parse_type(ts)?;
246	        // Handle array suffix: sizeof(int[4]), sizeof(char[16])
247	        while ts.eat(TokenKind::LBracket) {
248	            let TokenKind::IntLit(size) = ts.peek().kind else {
249	                return Err(CompileError::new(
250	                    "expected array size in sizeof",
251	                    Some(ts.current_span()),
252	                ));
253	            };
254	            ts.advance();
255	            ts.expect(TokenKind::RBracket)?;
256	            ty = Type::Array(Box::new(ty), size as usize);
257	        }
258	        ts.expect(TokenKind::RParen)?;
259	        return Ok(Expr::IntLit(ty.size()));
260	    }
261	    // sizeof(expr) -- no type info available, assume int-sized
262	    let _expr = parse_unary(ts)?;
263	    ts.expect(TokenKind::RParen)?;
264	    Ok(Expr::IntLit(3))
265	}
